require "common.custom.CustomShopBlock"
require "common.custom.CustomShopEffectArrow"
require "common.custom.CustomShopAction"
require "common.custom.CustomShopFootprint"
require "common.custom.CustomShopSwordLight"
require "common.custom.CustomShopPet"
require "common.custom.CustomShopCloth"

local function checkPlayerAndGoods(userId, goodsId)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    local goods = CustomShopConfig:getGoodsConfig(goodsId)
    if not goods then
        return
    end
    return player, goods
end

local function checkPlayerFirstInit(player)
    if TableUtil.getTableSize(player.custom_goods) ~= 0 then
        return
    end
    local settings = CustomShopConfig:getCustomShop()
    for _, setting in pairs(settings) do
        for _, tab in pairs(setting.tabs) do
            local equipCount = CustomShopConfig:getEquipCount(tab.TabId)
            for _, goods in pairs(tab.GoodsList) do
                if goods.Default then
                    local group = player.custom_goods[tostring(goods.TabId)] or {}
                    player.custom_goods[tostring(goods.TabId)] = group
                    if equipCount > 0 then
                        group[tostring(goods.Id)] = { goods.Id, CustomShopGoodsStatus.Equiped, goods.Time }
                    else
                        group[tostring(goods.Id)] = { goods.Id, CustomShopGoodsStatus.UnEquip, goods.Time }
                    end
                    equipCount = equipCount - 1
                end
            end
        end
    end
end

function CustomShop:init()
    EventObservable:registerDataCallBack("BuyCustomGoods", function(userId, goodsId)
        local player, goods = checkPlayerAndGoods(userId, goodsId)
        if not player then
            return
        end
        CustomShop:onBuyGoods(player, goods, false, CustomShopGoodsGetWay.Buy)
    end)

    EventObservable:registerDataCallBack("UnloadCustomGoods", function(userId, goodsId)
        local player, goods = checkPlayerAndGoods(userId, goodsId)
        if not player then
            return
        end
        CustomShop:onUnloadGoods(player, goods)
    end)

    EventObservable:registerDataCallBack("EquipCustomGoods", function(userId, goodsId)
        local player, goods = checkPlayerAndGoods(userId, goodsId)
        if not player then
            return
        end
        CustomShop:onEquipGoods(player, goods)
    end)
end

CustomShop:init()

function CustomShop:onSyncPlayerAllGoods(player)
    checkPlayerFirstInit(player)
    local result = {}
    for TabId, group in pairs(player.custom_goods) do
        local remove = {}
        local equipCount = CustomShopConfig:getEquipCount(TabId)
        for goodsId, goods in pairs(group) do
            if goods[CustomGoodsIndex.Time] ~= -1 and os.time() > goods[CustomGoodsIndex.Time] then
                table.insert(remove, goodsId)
            else
                if goods[CustomGoodsIndex.Status] == CustomShopGoodsStatus.Equiped then
                    local _goods = CustomShopConfig:getGoodsConfig(goodsId)
                    if _goods then
                        CustomShop:callModuleFunc("onEquipGoods", CustomShopConfig:getGoodsType(_goods), player, _goods)
                    end
                end
                table.insert(result, goods)
            end
            --if goods[CustomGoodsIndex.Status] == CustomShopGoodsStatus.Equiped then
            --    if equipCount > 0 then
            --        equipCount = equipCount - 1
            --    else
            --        goods[CustomGoodsIndex.Status] = CustomShopGoodsStatus.UnEquip
            --    end
            --end
        end
        for _, goodsId in pairs(remove) do
            group[goodsId] = nil
        end
    end
    if #result > 0 then
        CustomShop:onPlayerGoodsChange(player, result)
    end
end

function CustomShop:onPlayerGoodsChange(player, goodsList)
    CommonPacketSender:sendCustomShopData(player.rakssid, goodsList)
end

local function onBuyGoodsSuccess(player, goods, getWay)
    local group = player.custom_goods[tostring(goods.TabId)] or {}
    local _goods = { goods.Id, CustomShopGoodsStatus.UnEquip, goods.Time, getWay }
    group[tostring(goods.Id)] = _goods
    CustomShop:onPlayerGoodsChange(player, { _goods })
    CommonPacketSender:sendBuyCustomGoodsSuccess(player.rakssid, goods.Id)
end

function CustomShop:onBuyGoods(player, goods, free, getWay)
    if goods.Price < 0 then
        return
    end
    local group = player.custom_goods[tostring(goods.TabId)] or {}
    player.custom_goods[tostring(goods.TabId)] = group
    for _, _goods in pairs(group) do
        if _goods[CustomGoodsIndex.Id] == goods.Id and _goods[CustomGoodsIndex.Time] ~= 0 then
            return ---已购买，无需再次购买
        end
    end
    if free then
        onBuyGoodsSuccess(player, goods, getWay)
        return true
    end
    if not MoneyUtil:checkHasMoney(player, Define.Money.DIAMOND, goods.DiscountPrices) then
        return
    end
    PayHelper.payDiamondsSync(player.userId, goods.Id, goods.DiscountPrices, function()
        onBuyGoodsSuccess(player, goods, getWay)
        return true
    end)
end

function CustomShop:onEquipGoods(player, goods)
    local group = player.custom_goods[tostring(goods.TabId)]
    if not group then
        return
    end
    local equipCount = CustomShopConfig:getEquipCount(goods.TabId)
    local result = {}
    if equipCount <= 1 then
        for _, _goods in pairs(group) do
            if _goods[CustomGoodsIndex.Status] == CustomShopGoodsStatus.Equiped then
                _goods[CustomGoodsIndex.Status] = CustomShopGoodsStatus.UnEquip
                table.insert(result, _goods)
                local goodsConfig = CustomShopConfig:getGoodsConfig(_goods[CustomGoodsIndex.Id])
                if goodsConfig then
                    CustomShop:callModuleFunc("onUnloadGoods", CustomShopConfig:getGoodsType(goods),
                            player, CustomShopConfig:getGoodsConfig(_goods[CustomGoodsIndex.Id]))
                end
            end
        end
    else
        local count = 0
        for _, _goods in pairs(group) do
            if _goods[CustomGoodsIndex.Status] == CustomShopGoodsStatus.Equiped then
                count = count + 1
            end
        end
        if count >= equipCount then
            return
        end
    end
    local _goods = group[tostring(goods.Id)]
    if not _goods or _goods.Time == 0 then
        return
    end
    if _goods[CustomGoodsIndex.Status] == CustomShopGoodsStatus.Equiped then
        return
    end
    CustomShop:callModuleFunc("onEquipGoods", CustomShopConfig:getGoodsType(goods), player, goods)
    _goods[CustomGoodsIndex.Status] = CustomShopGoodsStatus.Equiped
    table.insert(result, _goods)
    CustomShop:onPlayerGoodsChange(player, result)
end

function CustomShop:onUnloadGoods(player, goods)
    local group = player.custom_goods[tostring(goods.TabId)]
    if not group then
        return
    end
    local _goods = group[tostring(goods.Id)]
    if not _goods or group[tostring(goods.Id)].Time == 0 then
        return
    end
    if _goods[CustomGoodsIndex.Status] == CustomShopGoodsStatus.UnEquip then
        return
    end
    _goods[CustomGoodsIndex.Status] = CustomShopGoodsStatus.UnEquip
    CustomShop:onPlayerGoodsChange(player, { _goods })
    CustomShop:callModuleFunc("onUnloadGoods", CustomShopConfig:getGoodsType(goods), player, goods)
end

function CustomShop:onRecycleGoods(player, goods)
    if not player.custom_goods[tostring(goods.TabId)] then
        return
    end
    local _goods = player.custom_goods[tostring(goods.TabId)][tostring(goods.Id)]
    if not _goods then
        return
    end
    if _goods[CustomGoodsIndex.GetWay] ~= CustomShopGoodsGetWay.TreasureChallenge then
        return
    end
    _goods[CustomGoodsIndex.Status] = CustomShopGoodsStatus.UnEquip
    _goods[CustomGoodsIndex.Time] = 0
    CustomShop:onPlayerGoodsChange(player, { _goods })
    CustomShop:callModuleFunc("onUnloadGoods", CustomShopConfig:getGoodsType(goods), player, goods)
end